import{_ as s,o as e,c as t,a5 as i}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：Boost 故障锁存与复位状态机（Fault Latch And Reset State Machine）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：Boost 故障锁存与复位状态机（Fault Latch And Reset State Machine）","tags":["power-electronics"],"status":"learning","summary":"故障锁存（fault latch）是指：一旦检测到严重故障，软件把故障码保存下来，并禁止功率输出，不能因为下一次采样恢复正常就自动重新运行。"},"headers":[],"relativePath":"content/power/concepts/embedded/boost-fault-state-machine.md","filePath":"content/power/concepts/embedded/boost-fault-state-machine.md","lastUpdated":null}'),l={name:"content/power/concepts/embedded/boost-fault-state-machine.md"};function n(o,a,p,h,c,d){return e(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="概念-boost-故障锁存与复位状态机-fault-latch-and-reset-state-machine" tabindex="-1">概念：Boost 故障锁存与复位状态机（Fault Latch And Reset State Machine） <a class="header-anchor" href="#概念-boost-故障锁存与复位状态机-fault-latch-and-reset-state-machine" aria-label="Permalink to &quot;概念：Boost 故障锁存与复位状态机（Fault Latch And Reset State Machine）&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>故障锁存（fault latch）是指：一旦检测到严重故障，软件把故障码保存下来，并禁止功率输出，不能因为下一次采样恢复正常就自动重新运行。</p><p>状态机（state machine）是把软件运行阶段显式分成有限状态的写法。本节使用三个状态：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>RUN -&gt; FAULT_LATCHED -&gt; RESET_WAIT -&gt; RUN</span></span></code></pre></div><p>本节仍是教学模型，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据；学习记录中也不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_2-ups-为什么需要它" tabindex="-1">2. UPS 为什么需要它 <a class="header-anchor" href="#_2-ups-为什么需要它" aria-label="Permalink to &quot;2. UPS 为什么需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）既要持续供电，也要避免危险输出。对过压、过流、母线异常等严重故障，软件不能只看瞬时采样值。原因是：</p><ul><li>故障可能很短，但已经暴露出硬件或负载风险。</li><li>自动恢复可能导致反复启停。</li><li>复位通常需要确认采样恢复、等待放电或降温、记录故障，再按状态机重新启动。</li></ul><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>故障锁存像配电柜里的跳闸。电压短暂恢复不等于可以立刻合闸。你需要先确认故障原因消失，再经过一个复位流程，最后才允许脉宽调制（pulse-width modulation / PWM）重新使能。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>简化状态转移可以写成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if state == RUN and Vout &gt; OV:</span></span>
<span class="line"><span>    fault = OV</span></span>
<span class="line"><span>    state = FAULT_LATCHED</span></span>
<span class="line"><span>    pwm_enable = 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if state == FAULT_LATCHED and reset_request:</span></span>
<span class="line"><span>    state = RESET_WAIT</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if state == RESET_WAIT and wait_time &gt;= reset_delay:</span></span>
<span class="line"><span>    fault = NONE</span></span>
<span class="line"><span>    state = RUN</span></span>
<span class="line"><span>    pwm_enable = 1</span></span></code></pre></div><p>这里的过压阈值（over-voltage threshold / OV）不是控制目标，而是保护边界。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>一个仿真任务是运行 <code>boost_fault_state_machine.py</code>，观察故障锁存、复位请求和 PWM 重新使能之间的时序关系：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\boost_fault_state_machine.py</span></span></code></pre></div><p>对比复位延时：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\boost_fault_state_machine.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">reset-delay</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.002</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\boost_fault_reset_2ms.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\boost_fault_state_machine.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">reset-delay</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.012</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\boost_fault_reset_12ms.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>观察四条曲线：</p><ul><li>输出电压 <code>Vout</code> 是否短暂超过过压阈值。</li><li>状态码是否从 <code>RUN</code> 进入 <code>FAULT_LATCHED</code>。</li><li>复位请求（reset request）出现后是否先进入 <code>RESET_WAIT</code>。</li><li>PWM 使能是否在故障期间为 0，复位延时结束后才恢复为 1。</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实 C 工程中，故障锁存与复位可能分布在：</p><ul><li><code>protection.c</code>：检测故障并产生故障码。</li><li><code>state_machine.c</code>：决定是否进入故障、等待复位、重新启动。</li><li><code>pwm.c</code>：执行软件关断或释放输出。</li><li><code>log.c</code> 或诊断模块：记录故障发生时间、故障码和关键采样值。</li></ul><p>读代码时不要只问“阈值是多少”。更重要的是追踪：故障码在哪里锁存、哪里清除、谁允许 PWM 重新打开。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：故障采样消失后就应该自动恢复。<br> 正确理解：严重故障通常要锁存，并等待明确复位流程。</p></li><li><p>错误理解：状态机只是写法问题。<br> 正确理解：状态机决定了系统什么时候允许输出，直接影响安全性和可调试性。</p></li><li><p>错误理解：复位按钮只负责清故障码。<br> 正确理解：复位还要检查条件、等待时间、确认输出处于安全状态。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释故障锁存（fault latch）和普通故障检测的区别。</li><li>能在仿真图中指出 <code>RUN</code>、<code>FAULT_LATCHED</code>、<code>RESET_WAIT</code> 三段。</li><li>能解释为什么 <code>Vout</code> 恢复正常后 PWM 仍然保持 0。</li><li>能说明复位请求（reset request）和复位延时（reset delay）不是同一件事。</li><li>能基于 <code>boost_fault_state_machine.py</code> 生成的图准备导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>默认仿真中，过压脉冲开始于多少 ms，持续多少 ms？</li><li>复位请求出现后，为什么不立刻回到 <code>RUN</code>？</li><li>把 <code>--reset-delay</code> 从 <code>0.002</code> 改成 <code>0.012</code> 后，哪一段状态持续时间变化最大？</li><li>如果故障码由 <code>protection.c</code> 产生，应该由哪个模块清除？为什么？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>boost_fault_state_machine.py</code> 看到过压脉冲结束后仍保持 <code>FAULT_LATCHED</code>。公司工程里哪些故障必须锁存，哪些允许自动恢复？</li><li>我看到复位请求后还要等待 <code>reset_delay</code> 才恢复 <code>RUN</code>。真实工程里复位延时通常基于什么条件设置？</li><li>我看到 PWM 使能在故障期间为 0。公司代码里软件关断、硬件比较器关断和驱动芯片使能之间如何分工？</li></ul>`,34)])])}const k=s(l,[["render",n]]);export{u as __pageData,k as default};
